import React, { useEffect } from 'react';

function ImpressaoListaAgendamentos({ disciplina, semestre, data, agendamentos }) {
  useEffect(() => {
    setTimeout(() => window.print(), 200); // Garante o render antes da impressão
  }, []);

  return (
    <div className="p-10 print:p-0">
      {/* Topo */}
      <div className="mb-8 text-center">
        <h1 className="text-2xl font-bold mb-1">Lista de Agendamentos</h1>
        <div className="mb-1">
          <span className="font-semibold">Disciplina: </span>{disciplina}
        </div>
        <div className="mb-1">
          <span className="font-semibold">Semestre: </span>{semestre}
        </div>
        <div>
          <span className="font-semibold">Data: </span>{data}
        </div>
      </div>

      {/* Grid */}
      <table className="min-w-full border text-sm print:text-xs">
        <thead>
          <tr className="bg-gray-100">
            <th className="border px-2 py-1">N°</th>
            <th className="border px-2 py-1">Operador</th>
            <th className="border px-2 py-1">Auxiliar</th>
            <th className="border px-2 py-1">Paciente</th>
            <th className="border px-2 py-1">Telefone</th>
            <th className="border px-2 py-1">Status</th>
          </tr>
        </thead>
        <tbody>
          {agendamentos && agendamentos.length > 0 ? agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx}>
              <td className="border px-2 py-1 text-center">{idx + 1}</td>
              <td className="border px-2 py-1">{ag.operadorNome}</td>
              <td className="border px-2 py-1">{ag.auxiliarNome}</td>
              <td className="border px-2 py-1">{ag.pacienteNome}</td>
              <td className="border px-2 py-1">{ag.telefone}</td>
              <td className="border px-2 py-1">{ag.status}</td>
            </tr>
          )) : (
            <tr>
              <td colSpan={6} className="text-center py-6 text-gray-400">Nenhum agendamento encontrado.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ImpressaoListaAgendamentos;

